import { useEffect, useState } from "react";
import axios from "axios";
import { getProtocols } from "../api/protocolsapi";
const BASE_URL =process.env.REACT_APP_API_URL;
//const MOCK_PROTOCOLS = ["MQTT", "MODBUS", "OPC-UA", "Modbus TCP"];

export const useProtocols = () => {
    const [protocols, setProtocols] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const url = `${process.env.REACT_APP_API_URL}`;
        console.log("Calling URL:", url);

        axios.get(getProtocols())
            .then(res => {
                // adjust this depending on what the API returns
                const data = res.data;
                if (Array.isArray(data)) {
                    setProtocols(data);
                } else if (data.protocols) {
                    setProtocols(data.protocols);
                } else {
                    setProtocols(MOCK_PROTOCOLS);
                }
            })
            .catch((err) => {
                console.log("API unavailable, using mock:", err.message);
                setProtocols(MOCK_PROTOCOLS);
                setError(null);
            })
            .finally(() => setLoading(false));
    }, []);

    return { protocols, loading, error };
};
